const STABLE_READINGS = 3;
const FRESH_MS = 15000;
const ZERO_OFF_MS = 300000;
const MIN_CHANGE_MS = 8000;
const CONTROLLED = {2:'light2',3:'fan1',4:'fan3',6:'fan4',7:'light1',8:'fan2'};
const TOPICS = {2:'lab/control/relay2/set',3:'lab/control/relay3/set',4:'lab/control/relay4/set',6:'lab/control/relay6/set',7:'lab/control/relay7/set',8:'lab/control/relay8/set'};
function m(topic,payload,retain=false){return {topic,payload:typeof payload==='string'?payload:JSON.stringify(payload),retain};}
function send(commands,diagnostics){node.send([commands.length?commands:null,diagnostics.length?diagnostics:null]);}
function clearZero(){context.set('zeroSince',0);}
function desired(stage){const s={2:'OFF',3:'OFF',4:'OFF',6:'OFF',7:'OFF',8:'OFF'};if(stage==='ONE'){s[2]='ON';s[7]='ON';}else if(stage==='TWO_THREE'){s[2]='ON';s[7]='ON';s[3]='ON';s[6]='ON';}else if(stage==='FOUR_PLUS'){for(const r of Object.keys(s))s[r]='ON';}return s;}
function stageFor(n){return n===0?'EMPTY':n===1?'ONE':n<4?'TWO_THREE':'FOUR_PLUS';}
function healthy(now){const last=context.get('lastVision')||0;return context.get('serviceOnline')===true&&context.get('sourceHealthy')===true&&last>0&&now-last<=FRESH_MS;}
function apply(stage,count,reason,now){const want=desired(stage),actual=context.get('actual')||{},last=context.get('lastCommand')||{},commands=[];for(const [relay,value] of Object.entries(want)){if(actual[relay]!==value&&last[relay]!==value){commands.push(m(TOPICS[relay],value,false));last[relay]=value;}}context.set('lastCommand',last);context.set('activeStage',stage);context.set('lastApply',now);context.set('pendingStage','');context.set('pendingReadings',0);send(commands,[m('lab/automation/intended_state',{publisher:'nodered-labos-safe',stage,count,relays:want,reason,timestamp:Math.floor(now/1000)},true),m('lab/automation/last_action',reason,true)]);node.status({fill:stage==='EMPTY'?'red':'green',shape:'dot',text:stage+' count='+count});}
const topic=String(msg.topic||''),now=Date.now(),diagnostics=[];
if(topic==='lab/automation/mode'){const mode=String(msg.payload).trim().toLowerCase();if(!['manual','monitor','auto'].includes(mode))return null;context.set('mode',mode);if(mode!=='auto')clearZero();send([], [m('lab/automation/mode_state',mode,true)]);node.status({fill:mode==='auto'?'green':mode==='monitor'?'yellow':'blue',shape:'ring',text:mode+' mode'});return null;}
if(topic==='lab/vision/status'){let v=String(msg.payload).toLowerCase();try{const o=typeof msg.payload==='object'?msg.payload:JSON.parse(String(msg.payload));v=String(o.status||v).toLowerCase();}catch(e){}context.set('serviceOnline',v==='online'||v==='healthy');if(v!=='online'&&v!=='healthy')clearZero();return null;}
if(topic==='lab/vision/source_status'){const v=String(msg.payload).toLowerCase();context.set('sourceHealthy',v==='healthy');if(v!=='healthy')clearZero();return null;}
if(topic==='lab/vision/heartbeat'){context.set('lastHeartbeat',now);return null;}
if(topic==='lab/control/status'){context.set('relayOnline',String(msg.payload).toLowerCase()==='online');return null;}
const sm=topic.match(/^lab\/control\/relay([1-8])\/state$/);if(sm){const relay=sm[1],actual=context.get('actual')||{};actual[relay]=String(msg.payload).toUpperCase();context.set('actual',actual);return null;}
if(topic==='lab/automation/internal/tick'){const ok=healthy(now),last=context.get('lastVision')||0,mode=context.get('mode')||'manual',count=context.get('latestCount');diagnostics.push(m('lab/automation/vision_health',ok?'healthy':'stale',true));diagnostics.push(m('lab/automation/vision_age_seconds',last?Math.floor((now-last)/1000):-1,true));if(!ok){clearZero();send([],diagnostics);return null;}const zeroSince=context.get('zeroSince')||0;if(mode==='auto'&&count===0&&zeroSince&&now-zeroSince>=ZERO_OFF_MS){apply('EMPTY',0,'Healthy zero continuously confirmed for five minutes',now);return null;}send([],diagnostics);return null;}
if(topic!=='lab/vision/people_count')return null;
let p=msg.payload;if(Buffer.isBuffer(p))p=p.toString();if(typeof p==='string'){try{p=JSON.parse(p);}catch(e){clearZero();send([],[m('lab/automation/warning','Invalid count JSON ignored; previous relay state preserved',false)]);return null;}}
let ts=Number(p&&p.timestamp);if(ts<100000000000)ts*=1000;const count=Number(p&&p.stable_count);if(!p||p.publisher!=='labvision-ai-pc'||p.source_healthy!==true||!Number.isInteger(count)||count<0||!Number.isFinite(ts)||Math.abs(now-ts)>FRESH_MS){clearZero();send([],[m('lab/automation/warning','Unauthorized, unhealthy, invalid, or stale count ignored; previous relay state preserved',false)]);return null;}
context.set('lastVision',now);context.set('latestCount',count);context.set('sourceHealthy',true);const mode=context.get('mode')||'manual',target=stageFor(count),want=desired(target);diagnostics.push(m('lab/automation/accepted_count',{publisher:'nodered-labos-safe',count,target,timestamp:Math.floor(now/1000)},false));
if(mode==='manual'){clearZero();send([],diagnostics);node.status({fill:'blue',shape:'ring',text:'manual count='+count});return null;}
if(mode==='monitor'){clearZero();diagnostics.push(m('lab/automation/intended_state',{publisher:'nodered-labos-safe',stage:target,count,relays:want,timestamp:Math.floor(now/1000)},true));send([],diagnostics);node.status({fill:'yellow',shape:'ring',text:'monitor '+target+' count='+count});return null;}
if(!healthy(now)){clearZero();send([],diagnostics);return null;}
if(count===0){let zeroSince=context.get('zeroSince')||0;if(!zeroSince){zeroSince=now;context.set('zeroSince',zeroSince);}diagnostics.push(m('lab/automation/zero_shutdown_remaining_seconds',Math.max(0,Math.ceil((ZERO_OFF_MS-(now-zeroSince))/1000)),true));send([],diagnostics);node.status({fill:'yellow',shape:'ring',text:'healthy zero; OFF after 5 min'});return null;}
clearZero();if(target===context.get('activeStage')){send([],diagnostics);return null;}let pending=context.get('pendingStage')||'',reads=context.get('pendingReadings')||0;if(target===pending)reads++;else{pending=target;reads=1;}context.set('pendingStage',pending);context.set('pendingReadings',reads);if(reads<STABLE_READINGS||now-(context.get('lastApply')||0)<MIN_CHANGE_MS){send([],diagnostics);node.status({fill:'yellow',shape:'ring',text:'checking '+target+' '+reads+'/'+STABLE_READINGS});return null;}apply(target,count,'Applied stable occupancy stage '+target,now);return null;
